                                            '\n'
                                            '# Update Project Progress\n'
                                            '\n'
                                            'Before finishing a task that changed code, tests, '
                                            'config, architecture, prompts, schemas, docs, or git '
                                            'workflow:\n'
                                            '\n'
                                            '1. Inspect:\n'
                                            '   ```bash\n'
                                            '   git status\n'
                                            '   git diff --name-only HEAD\n'
                                            '   git diff HEAD\n'
                                            '   ```\n'
                                            '2. Update:\n'
                                            '   - `docs/agent/04_TASK_HANDOFF.md`\n'
                                            '   - `docs/agent/05_PROGRESS.md`\n'
                                            '   - `docs/agent/11_AGENT_STATE.md`\n'
                                            '   - `docs/agent/12_AGENT_BOARD.md` when handing work '
                                            'to another agent\n'
